using Microsoft.ML;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public static class ChurnModelTrainer
{
    public static void TrainAndSave(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<CustomerData>(
            dataPath, hasHeader: true, separatorChar: ',');

        var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
            .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.Transforms.CopyColumns("Label", "Churned"))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        long rowCount = data.GetColumn<bool>("Churned").LongCount();

        if (rowCount >= 10)
        {
            // Enough data for a proper train/test split
            var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
            var model = pipeline.Fit(split.TrainSet);

            var predictions = model.Transform(split.TestSet);
            var metrics = mlContext.BinaryClassification.Evaluate(predictions);
            Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                              $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

            mlContext.Model.Save(model, data.Schema, modelPath);
        }
        else
        {
            // Small dataset — use cross-validation then train on all data
            Console.WriteLine($"Small dataset ({rowCount} rows) — using cross-validation.");
            var cvResults = mlContext.BinaryClassification.CrossValidate(data, pipeline, numberOfFolds: (int)Math.Min(rowCount, 5));
            var avgAccuracy = cvResults.Average(r => r.Metrics.Accuracy);
            Console.WriteLine($"Cross-validation avg accuracy: {avgAccuracy:F4}");

            var model = pipeline.Fit(data);
            mlContext.Model.Save(model, data.Schema, modelPath);
        }

        Console.WriteLine($"Model saved to {modelPath}");
    }
}

